128	// Reads up to `dst_max` bytes from a register handle. Returns the byte
129	// count written (0 on failure or NULL handle). Used for vector regs whose
130	// width = vlenb bytes.
131	static size_t read_reg_bytes(struct qemu_plugin_register *h,
132	                             uint8_t *dst, size_t dst_max)
133	{
134	    if (!h || dst_max == 0) return 0;
135	    g_autoptr(GByteArray) buf = g_byte_array_new();
136	    int sz = qemu_plugin_read_register(h, buf);
137	    if (sz <= 0) return 0;
138	    size_t n = (size_t) sz < dst_max ? (size_t) sz : dst_max;
139	    memcpy(dst, buf->data, n);
140	    return n;
141	}
