143	// Atomic on POSIX: write to .tmp, fsync, rename.
144	static int write_state_atomic(const struct hybrid_state_v1 *s, const char *path)
145	{
146	    char tmp[PATH_MAX];
147	    g_snprintf(tmp, sizeof(tmp), "%s.tmp.%d", path, (int) getpid());
148	    int fd = open(tmp, O_WRONLY | O_CREAT | O_TRUNC, 0600);
149	    if (fd < 0) {
150	        perror("hybrid_handoff: open tmp");
151	        return -1;
152	    }
153	    ssize_t want = (ssize_t) sizeof(*s);
154	    ssize_t got = write(fd, s, sizeof(*s));
155	    if (got != want) {
156	        perror("hybrid_handoff: write");
157	        close(fd);
158	        unlink(tmp);
159	        return -1;
160	    }
161	    fsync(fd);
162	    close(fd);
163	    if (rename(tmp, path) != 0) {
164	        perror("hybrid_handoff: rename");
165	        unlink(tmp);
166	        return -1;
167	    }
168	    return 0;
169	}
