171	static void on_handoff(unsigned int vcpu_idx, void *udata)
172	{
173	    hybrid_handoff_kind kind = (hybrid_handoff_kind) (uintptr_t) udata;
174	    if (kind != HYBRID_HANDOFF_ENTER) return;
175	
176	    VcpuRegs *v = qemu_plugin_scoreboard_find(vcpu_state, vcpu_idx);
177	    resolve_handles(v);
178	    struct hybrid_state_v1 s = {0};
179	    s.magic   = HYBRID_STATE_MAGIC;
180	    s.version = HYBRID_STATE_VERSION;
181	    s.flags   = HYBRID_FLAG_RV64;
182	    s.hart_id = vcpu_idx;
183	    s.priv    = 3;
184	    s.pc      = read_reg64(v->pc);
185	    for (int i = 0; i < 32; i++) s.gpr[i] = read_reg64(v->gpr[i]);
186	
187	    // Floating-point: only set FP flag if at least one handle was bound,
188	    // i.e. QEMU advertised the FPU feature (D extension).
189	    int has_fp = 0;
190	    for (int i = 0; i < 32; i++) {
191	        s.fpr[i] = read_reg64(v->fpr[i]);
192	        if (v->fpr[i]) has_fp = 1;
193	    }
194	    if (has_fp) s.flags |= HYBRID_FLAG_FP;
195	
196	    s.mstatus  = read_reg64(v->mstatus);
197	    s.mepc     = read_reg64(v->mepc);
198	    s.mtvec    = read_reg64(v->mtvec);
199	    s.mcause   = read_reg64(v->mcause);
200	    s.mtval    = read_reg64(v->mtval);
201	    s.mscratch = read_reg64(v->mscratch);
202	    s.medeleg  = read_reg64(v->medeleg);
203	    s.mideleg  = read_reg64(v->mideleg);
204	    s.mip      = read_reg64(v->mip);
205	    s.mie      = read_reg64(v->mie);
206	    s.mcycle   = read_reg64(v->mcycle);
207	    s.minstret = read_reg64(v->minstret);
208	    s.satp     = read_reg64(v->satp);
209	
210	    for (int i = 0; i < HYBRID_PMP_CFG_NUM; i++)
211	        s.pmpcfg[i] = read_reg64(v->pmpcfg[i]);
212	    for (int i = 0; i < HYBRID_PMP_ADDR_NUM; i++)
213	        s.pmpaddr[i] = read_reg64(v->pmpaddr[i]);
214	
215	    // Vector: only set V flag if QEMU advertised the V extension. vlenb
216	    // bounds the per-register byte count copied into vreg[].
217	    s.vstart = read_reg64(v->vstart);
218	    s.vtype  = read_reg64(v->vtype);
219	    s.vl     = read_reg64(v->vl);
220	    s.vlenb  = read_reg64(v->vlenb);
221	    if (v->vlenb && s.vlenb > 0) {
222	        s.flags |= HYBRID_FLAG_V;
223	        size_t bytes = s.vlenb < HYBRID_VLEN_BYTES_MAX
224	                     ? (size_t) s.vlenb
225	                     : (size_t) HYBRID_VLEN_BYTES_MAX;
226	        for (int i = 0; i < 32; i++)
227	            (void) read_reg_bytes(v->vreg[i],
228	                                  &s.vreg[(size_t) i * HYBRID_VLEN_BYTES_MAX],
229	                                  bytes);
230	    }
231	
232	    if (write_state_atomic(&s, outfile_path) != 0) {
233	        fprintf(stderr, "hybrid_handoff: failed to write state file\n");
234	        exit(2);
235	    }
236	    fprintf(stderr,
237	            "hybrid_handoff: drained state to %s (pc=%#" PRIx64 "), exiting\n",
238	            outfile_path, s.pc);
239	    exit(0);
240	}
